    "date": "2026-02-13",
    "topic": "Edited Transcript of the Reserve Bank of India’s Post-Monetary Policy Press Conference: February 6, 2026 (Friday) - ",
    "topicTag": "Economy",
    "source": "RBI Speeches",
    "url": "https://www.rbi.org.in/scripts/BS_SpeechesView.aspx?id=1543",
